// ====== WARM-UP RAMP + SHARED DAILY CAP + PICK NEXT NEW LEAD ======
// Protects the sending account: starts low and ramps up over 4 weeks.
const sd = $getWorkflowStaticData('global');
const now = new Date();
if (!sd.startDate) sd.startDate = now.toISOString();
const dayNum = Math.floor((now - new Date(sd.startDate)) / 864e5) + 1;

let cap;
if (dayNum <= 7) cap = 5;        // Week 1
else if (dayNum <= 14) cap = 8;  // Week 2
else if (dayNum <= 21) cap = 12; // Week 3
else cap = 15;                   // Week 4+ (raise slowly to 18-20 later)

const today = now.toISOString().slice(0, 10);
const rows = items.map(i => i.json);
// Total emails sent today across BOTH new + follow-up flows (shared cap).
const sentToday = rows.filter(r => String(r.last_sent_at || '').slice(0, 10) === today).length;
if (sentToday >= cap) {
  return [{ json: { proceed: false, reason: 'Daily cap reached', cap, sentToday, dayNum } }];
}

// Pick the next brand-new lead (no status, stage 0) with a valid email.
const next = rows.find(r => {
  const status = String(r.status || '').trim().toLowerCase();
  const stage = Number(r.stage || 0);
  const email = String(r.email || '').trim();
  return email.includes('@') && (status === '' || status === 'pending') && (!stage || stage === 0);
});
if (!next) {
  return [{ json: { proceed: false, reason: 'No new leads', cap, sentToday, dayNum } }];
}
return [{ json: { proceed: true, cap, sentToday, dayNum, lead: next, row_number: next.row_number } }];

// ============================================================
// ====== EDIT YOUR IDENTITY + OFFER HERE (4 lines only) ======
const SENDER_NAME = 'Your Name';
const OFFER = 'I build AI agent systems and outbound automation for businesses, done-for-you';
const PROOF = 'I recently added $20K for a SaaS client by building them an outbound system';
const GUARANTEE = 'I can guarantee a clear result or I work for free until I deliver it';
// ============================================================

const lead = $json.lead || {};

const system = `You are ${SENDER_NAME} writing a SHORT, casual, confident cold email to one prospect. ${OFFER}.

STYLE RULES:
- 3 to 4 short sentences total. Never more.
- Plain text only. Sound like one founder writing to another: confident, direct, human, not salesy.
- Open with "Hey [first name]," then ONE genuine, specific sentence about their company based on the company description provided. Make it real and personal, never generic flattery.
- NEVER use em-dashes or double hyphens. Use commas, periods, or new sentences instead.
- No buzzwords, no exclamation marks, no marketing-speak, no ALL CAPS, no links, no images.
- Use ONLY the true facts below. Never invent results, numbers, clients, or claims.
- Close with one soft call to action: offer a quick 15 minute call later today or tomorrow, and say you will send a meeting link. Do NOT paste a link.
- Sign off on its own line with just: ${SENDER_NAME}

TRUE FACTS (do not go beyond these):
- ${PROOF}.
- ${GUARANTEE}.

Output STRICT JSON only, no markdown, exactly:
{"subject": "...", "body": "..."}
The subject must be casual, lowercase-ish, under 5 words, and must not look like an ad.`;

const userMsg = `Write the cold email now for this lead.
First name: ${lead.first_name || 'there'}
Company: ${lead.company || ''}
Title: ${lead.title || ''}
Industry: ${lead.industry || ''}
Company description (use this for the personalized opening line): ${lead.company_description || 'no description available'}

If no company description is available, open with a genuine line based on their title or industry instead. Keep it to 3 or 4 short sentences. No em-dashes. Sign off as ${SENDER_NAME}.`;

const body = { model: 'claude-sonnet-4-6', max_tokens: 500, system, messages: [{ role: 'user', content: userMsg }] };
return [{ json: { body } }];

// Parse Claude's JSON reply, re-attach the lead's row + email.
const resp = $json;
let text = '';
try { text = resp.content && resp.content[0] && resp.content[0].text ? resp.content[0].text : ''; } catch (e) { text = ''; }
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let p;
try { p = JSON.parse(text); } catch (e) { p = { subject: 'quick question', body: text || 'Hi, reaching out.' }; }

const d = $('Decide Initial').item.json;
const lead = d.lead || {};
return [{ json: {
  to: lead.email,
  first_name: lead.first_name || '',
  company: lead.company || '',
  row_number: d.row_number,
  subject: String(p.subject || 'quick question').slice(0, 120),
  body: String(p.body || '').trim()
} }];

// ====== SHARED DAILY CAP + PICK NEXT LEAD WHOSE FOLLOW-UP IS DUE ======
const sd = $getWorkflowStaticData('global');
const now = new Date();
if (!sd.startDate) sd.startDate = now.toISOString();
const dayNum = Math.floor((now - new Date(sd.startDate)) / 864e5) + 1;

let cap;
if (dayNum <= 7) cap = 5;
else if (dayNum <= 14) cap = 8;
else if (dayNum <= 21) cap = 12;
else cap = 15;

const today = now.toISOString().slice(0, 10);
const rows = items.map(i => i.json);
const sentToday = rows.filter(r => String(r.last_sent_at || '').slice(0, 10) === today).length;
if (sentToday >= cap) {
  return [{ json: { proceed: false, reason: 'Daily cap reached' } }];
}

// Days to wait before each follow-up. stage 1 -> wait before 2nd email; stage 2 -> before 3rd.
const DELAY = { 1: 3, 2: 4 };
const daysSince = ts => ts ? (now - new Date(ts)) / 864e5 : 999;

const next = rows.find(r => {
  const status = String(r.status || '').trim().toLowerCase();
  const stage = Number(r.stage || 0);
  const email = String(r.email || '').trim();
  return email.includes('@') && status === 'active' && (stage === 1 || stage === 2) && daysSince(r.last_sent_at) >= DELAY[stage];
});
if (!next) {
  return [{ json: { proceed: false, reason: 'No follow-ups due' } }];
}
return [{ json: {
  proceed: true, cap, sentToday,
  lead: next, row_number: next.row_number,
  stage: Number(next.stage || 0),
  message_id: next.message_id,
  thread_id: next.thread_id
} }];

// ====== EDIT YOUR NAME HERE ======
const SENDER_NAME = 'Your Name';
// =================================

const lead = $json.lead || {};
const stage = Number($json.stage); // 1 = sending 2nd email, 2 = sending 3rd (final) email
const fuNum = stage;

const system = `You are ${SENDER_NAME} writing a SHORT follow-up to a cold email the prospect did not reply to. This is follow-up number ${fuNum} of 2.

RULES:
- 1 to 3 sentences only. Shorter than a first email.
- Friendly and low pressure. No guilt, no "just bumping this", no pushiness.
- Add ONE new angle, a quick proof point, or a simple yes or no question. Do NOT repeat the whole pitch.
- If this is follow-up number 2, make it a short, polite final check-in and offer to close the loop.
- NEVER use em-dashes or double hyphens. No links, no images. Plain text.
- Sign off on its own line with just: ${SENDER_NAME}

Output STRICT JSON only, no markdown, exactly:
{"subject": "", "body": "..."}
Leave subject as an empty string, the email is sent as a reply in the same thread.`;

const userMsg = `Prospect first name: ${lead.first_name || 'there'}
Company: ${lead.company || ''}
What they do: ${lead.company_description || 'unknown'}`;

const body = { model: 'claude-sonnet-4-6', max_tokens: 300, system, messages: [{ role: 'user', content: userMsg }] };
return [{ json: { body } }];

const resp = $json;
let text = '';
try { text = resp.content && resp.content[0] && resp.content[0].text ? resp.content[0].text : ''; } catch (e) { text = ''; }
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let p;
try { p = JSON.parse(text); } catch (e) { p = { subject: '', body: text || 'Just following up in case this is useful.' }; }

const d = $('Decide Follow-up').item.json;
return [{ json: {
  message_id: d.message_id,
  thread_id: d.thread_id,
  row_number: d.row_number,
  stage: d.stage,
  next_stage: Number(d.stage) + 1,
  body: String(p.body || '').trim()
} }];

// Collect unique sender email addresses from recent inbox messages.
const emails = items.map(i => {
  const f = i.json.from || i.json.From || '';
  const m = String(f).match(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/);
  return m ? m[0].toLowerCase() : null;
}).filter(Boolean);
return [{ json: { senders: Array.from(new Set(emails)) } }];

// Any 'active' lead who shows up as an inbox sender has replied -> mark 'replied'
// so the follow-up flow stops emailing them.
const senders = $('Extract Reply Senders').item.json.senders || [];
const set = new Set(senders.map(s => String(s).toLowerCase()));
const rows = items.map(i => i.json);
const out = rows.filter(r => {
  const email = String(r.email || '').trim().toLowerCase();
  const status = String(r.status || '').trim().toLowerCase();
  return email && set.has(email) && status === 'active';
}).map(r => ({ json: { row_number: r.row_number, status: 'replied' } }));
return out;
